def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 5):
                power = ratio ** (3 * k)
                denom = k * 2 + (k % 2)*0.5
                penalty += power / denom
                if penalty > 1e6:
                    break
            base = ratio ** 4
            priorities[i] = base + penalty
            if item > capacity * 2:
                priorities[i] += (item - capacity * 2) ** 2 / (capacity + 1)
        elif 0 < ratio <= 1:
            score = 0
            alternating = [1, -1, 1, -1, 1, -1, 1]
            for j in range(1, 8):
                sign = alternating[j-1]
                term = sign * (ratio ** j) / j
                score += term
            if ratio < 0.2:
                multiplier = 20
            elif ratio < 0.5:
                multiplier = 12
            elif ratio < 0.75:
                multiplier = 8
            else:
                multiplier = 4
            priorities[i] = abs(score) * multiplier
            extra = 0
            for m in range(1, 5):
                extra += ((-1)**m) * (ratio ** m) / (m + 2)
            priorities[i] += max(extra, 0)
            if ratio > 0.9:
                spike = 0
                for q in range(1, 10):
                    spike += (ratio ** q) / (q ** 2 + 1)
                priorities[i] += spike / 5
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    max_priority = np.max(priorities[np.isfinite(priorities)])
    if max_priority > 0:
        for idx in range(len(priorities)):
            if not np.isfinite(priorities[idx]):
                continue
            val = priorities[idx] / max_priority
            norm_val = val / (1 + val ** 0.5)
            priorities[idx] = norm_val
    return priorities
